const html = $input.first().json.body;

const csrfMatch = html.match(/name="--form-session-key"\s+value="([^"]+)"/);
const csrfToken = csrfMatch ? csrfMatch[1] : '';

if (!csrfToken) throw new Error('Could not extract CSRF token from form');

return [{ json: { csrfToken } }];

const inquiry = $input.all()[0];
const webhookData = $('Webhook').first();

const fields = { ...inquiry.json };
if (webhookData.json.body) {
  Object.assign(fields, webhookData.json.body);
}

const lines = fields.lines || [];
const formParams = {};

formParams['-table'] = 'inquiries';
formParams['-action'] = 'new';
formParams['--form-session-key'] = fields.csrfToken;
formParams['--no-query'] = '1';
formParams['_qf__new_inquiries_record_form'] = '1';
formParams['new_inquiries_record_form'] = '1';

const textFields = [
  'inquiry_type', 'from_email', 'from_name', 'from_company',
  'contact_number', 'status', 'user_id', 'inquiry_id',
  'delivery', 'delivery_time', 'delivery_address', 'delivery_location',
  'return_time', 'del_buffer', 'ret_buffer', 'city',
  'shipping_method_id', 'delivery_charges', 'adhoc_discount',
  'discount_id', 'booked_status', 'closure_reason',
  'internal_notes', 'contact_notes', 'followup_notes',
  'instructions_by_cust', 'notes_for_frontoffice',
  'notes_for_inventory', 'notes_for_logistics',
  'order_internal_notes', 'trade_rental', '__trade_rental'
];

for (const f of textFields) {
  const val = fields[f];
  if (val !== undefined && val !== null && val !== '') {
    formParams[f] = val;
  }
}

const dateFields = ['delivery_date', 'booking_release_date', 'received_on', 'return_date', 'followup_date'];
for (const df of dateFields) {
  const val = fields[df];
  if (val) {
    if (typeof val === 'object') {
      if (val.d) formParams[`${df}[d]`] = val.d;
      if (val.M) formParams[`${df}[M]`] = val.M;
      if (val.Y) formParams[`${df}[Y]`] = val.Y;
    } else if (typeof val === 'string' && val.includes('-')) {
      const parts = val.split('-');
      if (parts.length === 3) {
        formParams[`${df}[Y]`] = parts[0];
        formParams[`${df}[M]`] = parts[1].replace(/^0/, '');
        formParams[`${df}[d]`] = parts[2].replace(/^0/, '');
      }
    }
  }
}

let lineIndex = 0;
for (const line of lines) {
  const prefix = `lines[${lineIndex}]`;
  formParams[`${prefix}[item_id]`] = line.item_id || '';
  formParams[`${prefix}[item_quantity]`] = line.item_quantity || '';
  formParams[`${prefix}[item_package_id]`] = line.item_package_id || '';
  formParams[`${prefix}[discount_id]`] = line.discount_id || '';
  formParams[`${prefix}[line_status]`] = line.line_status || '';
  formParams[`${prefix}[__id__]`] = 'new';
  lineIndex++;
}

if (lines.length === 0) {
  formParams['lines[0][__id__]'] = 'new';
}

formParams['lines[__loaded__]'] = String(lineIndex || 1);

return [{ json: formParams }];

const response = $input.first().json;
const responseBody = typeof response.body === 'string' ? response.body : JSON.stringify(response.body);

const success = responseBody.includes('inquiry_id')
  || responseBody.includes('Record saved')
  || !responseBody.includes('Please Select');

return [{
  json: {
    success,
    message: success ? 'Inquiry submitted successfully' : 'Submission may have failed',
    responsePreview: responseBody.substring(0, 500)
  }
}];
